import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Login from './pages/Login';
import Home from './pages/Home';
import Sidebar from './components/Sidebar';
import DanhSachCoSo from './pages/DanhSachCoSo';
import KhaiBaoCoSo from './pages/KhaiBaoCoSo';

function AppLayout() {
  return (
    <div className="flex">
      <Sidebar />
      <div className="flex-1 p-4">
        <Routes>
          <Route path="/" element={<DanhSachCoSo />} />
          <Route path="/khai-bao" element={<KhaiBaoCoSo />} />
          <Route path="/*" element={<Home />} />
        </Routes>
      </div>
    </div>
  );
}

function App() {
  const token = localStorage.getItem("token");

  return (
    <Router>
      <Routes>
        <Route path="/login" element={<Login />} />
        <Route
          path="/*"
          element={token ? <AppLayout /> : <Navigate to="/login" replace />}
        />
      </Routes>
    </Router>
  );
}

export default App;
